import{_ as d,c as o,o as r,aj as p}from"./chunks/framework.CynFBi0q.js";const s=JSON.parse('{"title":"第4章 收集需求，明确产品定位","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_4.md","filePath":"handbook/ai-product/chapter_4.md","lastUpdated":1782008855000}'),a={name:"handbook/ai-product/chapter_4.md"};function e(h,t,u,n,l,q){return r(),o("div",null,[...t[0]||(t[0]=[p('<h1 id="第4章-收集需求-明确产品定位" tabindex="-1">第4章 收集需求，明确产品定位 <a class="header-anchor" href="#第4章-收集需求-明确产品定位" aria-label="Permalink to “第4章 收集需求，明确产品定位”">​</a></h1><p>做了4年产品经理，我最深的体会是：不是所有的需求都值得做，也不是所有的产品都值得活下来。产品经理70%的价值，体现在&quot;判断什么不该做&quot;这件事上。</p><p>我是怕浪猫，这一章不讲玄学，只讲实操——用户调研怎么做、需求怎么管理、产品怎么定位，一套方法论拿走直接用。</p><h2 id="_4-1-用户调研与需求收集" tabindex="-1">4.1 用户调研与需求收集 <a class="header-anchor" href="#_4-1-用户调研与需求收集" aria-label="Permalink to “4.1 用户调研与需求收集”">​</a></h2><h3 id="_4-1-1-常见用户调研方法概览" tabindex="-1">4.1.1 常见用户调研方法概览 <a class="header-anchor" href="#_4-1-1-常见用户调研方法概览" aria-label="Permalink to “4.1.1 常见用户调研方法概览”">​</a></h3><p>用户调研的方法很多，但大部分产品经理都用不对。原因很简单——没有针对调研的目的选择正确的方法。</p><p>调研的目的可以分为三类：</p><p><strong>第一类：探索性调研——我们不知道问题在哪</strong></p><p>目的是发现用户的行为模式、痛点和机会点。这时候要用的方法偏向&quot;开放式&quot;——不做预设，去发现。</p><p><strong>第二类：验证性调研——我们有了假设需要验证</strong></p><p>目的是验证某个判断是否成立。这时候要用的方法偏向&quot;结构化&quot;——有明确的问题，需要统计意义上的结论。</p><p><strong>第三类：监测性调研——已经上线了需要跟踪</strong></p><p>目的是持续监控产品的使用情况和用户满意度。这时候要用的方法偏向&quot;定量化&quot;——持续采集数据，跟踪变化趋势。</p><p><strong>方法选择对照表</strong></p><table tabindex="0"><thead><tr><th>方法</th><th>用途</th><th>样本量</th><th>时间成本</th><th>信息深度</th></tr></thead><tbody><tr><td>用户访谈</td><td>探索、深度理解</td><td>5-15人</td><td>高</td><td>极深</td></tr><tr><td>焦点小组</td><td>探索、群体互动</td><td>6-8人/组</td><td>中</td><td>中等</td></tr><tr><td>问卷调研</td><td>验证、量化</td><td>100+人</td><td>低</td><td>浅</td></tr><tr><td>可用性测试</td><td>验证、优化</td><td>5-8人</td><td>中</td><td>深</td></tr><tr><td>日志分析</td><td>监测、量化</td><td>所有用户</td><td>低</td><td>行为层面</td></tr><tr><td>A/B测试</td><td>验证、择优</td><td>大量用户</td><td>中</td><td>结果层面</td></tr></tbody></table><blockquote><p>调研方法没有&quot;最好的&quot;，只有&quot;最合适的&quot;。探索阶段做深度访谈，验证阶段做AB测试，监测阶段看数据——方法服务于目标。</p></blockquote><h3 id="_4-1-2-用户访谈-设计与执行" tabindex="-1">4.1.2 用户访谈：设计与执行 <a class="header-anchor" href="#_4-1-2-用户访谈-设计与执行" aria-label="Permalink to “4.1.2 用户访谈：设计与执行”">​</a></h3><p>用户访谈是产品经理的基本功。好的用户访谈像剥洋葱——每一层揭开，离用户的真实需求更近一步。</p><p><strong>访谈前的准备</strong></p><p>第一，明确访谈目标。你想验证什么假设？想了解用户的什么行为？目标越清晰，访谈越有产出。</p><p>第二，筛选合适的用户。访谈对象要满足三个条件：目标用户群体内、有一定使用经验、愿意开口说话。你可以从后台筛选高频用户，也可以找运营推荐活跃用户，或者通过问卷招募。</p><p>第三，设计访谈提纲。提纲不是&quot;问题清单&quot;，是&quot;话题方向&quot;。</p><p>好的访谈提纲包含三类问题：</p><table tabindex="0"><thead><tr><th>问题类型</th><th>目的</th><th>示例</th></tr></thead><tbody><tr><td>开场问题</td><td>建立信任、了解背景</td><td>&quot;你平时是怎么做XXX的？&quot;</td></tr><tr><td>探索问题</td><td>深入了解行为和方法</td><td>&quot;能详细说说这次是怎么完成的吗？&quot;</td></tr><tr><td>价值问题</td><td>评估功能的价值和优先级</td><td>&quot;如果这个功能没有了，你会有什么感受？&quot;</td></tr></tbody></table><p><strong>访谈中的技巧</strong></p><p>技巧一：多听少说。好的访谈里，访谈者说20%，用户说80%。你的任务是引导，不是表达。</p><p>技巧二：追问不满足于表面回答。用户说&quot;这个功能好用&quot;，你要追问&quot;好在哪&quot;；用户说&quot;很方便&quot;，你要追问&quot;比你之前的方法方便在哪&quot;。追到第三层，才能看到真实需求。</p><p>技巧三：避免引导性问题。&quot;这个功能你觉得怎么样&quot;比&quot;你觉得这个功能有用吗&quot;好得多。引导性问题会让用户顺着你的思路走，而不是表达真实想法。</p><p>技巧四：关注具体行为，不问主观判断。&quot;你上次使用这个功能是什么场景&quot;比&quot;你喜欢这个功能吗&quot;更有价值。</p><p>技巧五：允许沉默。用户思考时的沉默是珍贵的，不要急着填补空白。有时候沉默几秒钟，用户会说出比之前更有价值的内容。</p><p><strong>访谈后的整理</strong></p><p>访谈结束后48小时内完成整理。整理的内容包括：</p><p>用户画像片段记录：年龄、职业、使用场景、核心诉求 关键语录摘录：用户原话往往比你的总结有说服力 行为模式提炼：用户在做什么、怎么做的、为什么这么做 痛点归类：哪些是高频痛点、哪些是核心痛点、哪些是可以接受的代价</p><blockquote><p>5个用户访谈就能发现80%的问题，但5个访谈发现的问题往往高度重叠。通过5个访谈可以验证&quot;问题是否存在&quot;，但不足以判断&quot;问题的普遍性和严重性&quot;。</p></blockquote><p><strong>用户访谈常见错误</strong></p><table tabindex="0"><thead><tr><th>错误</th><th>后果</th><th>纠正方法</th></tr></thead><tbody><tr><td>问引导性问题</td><td>得到虚假结论</td><td>用开放式问题替代 &quot;你觉得&quot;</td></tr><tr><td>打断用户发言</td><td>丢失深层信息</td><td>保持沉默，等用户说完</td></tr><tr><td>选择性记录</td><td>信息偏差</td><td>全程录音，事后完整整理</td></tr><tr><td>样本偏差</td><td>结论不适用于目标群体</td><td>轮换不同特征的用户</td></tr><tr><td>过度解读</td><td>把个案当趋势</td><td>结合定量数据交叉验证</td></tr></tbody></table><h3 id="_4-1-3-问卷调查-设计与投放" tabindex="-1">4.1.3 问卷调查：设计与投放 <a class="header-anchor" href="#_4-1-3-问卷调查-设计与投放" aria-label="Permalink to “4.1.3 问卷调查：设计与投放”">​</a></h3><p>问卷调研适合验证假设和量化数据，但不适合探索未知。</p><p><strong>问卷设计五原则</strong></p><p>原则一：问题不要超过15个。超过15个问题，完成率断崖式下降。每个问题都要问自己：这个问题去掉会不会影响结论？</p><p>原则二：先易后难。基本信息放最后（年龄、职业等），核心问题放前面。用户刚打开问卷时耐心最足，到后面耐心下降，填写质量下降。</p><p>原则三：避免模糊表述。&quot;你平均每天使用几次&quot;比&quot;你经常使用吗&quot;好。具体的问题才能得到具体的答案。</p><p>原则四：选项要互斥且穷尽。&quot;未婚/已婚/离异/丧偶&quot;是互斥务尽的。&quot;小于1小时/1-3小时/3-5小时/5小时以上&quot;存在边界不清晰的问题——3小时算哪个选项？应该写成&quot;不足1小时/1小时到不满3小时/3小时到不满5小时/5小时及以上&quot;。</p><p>原则五：不设引导性选项。&quot;很好/好/一般/差/很差&quot;比&quot;很好/不错/还行/不太好/很差&quot;更中性，没有情感倾向。</p><p><strong>问卷投放渠道</strong></p><p>不同渠道的样本偏差不同。你需要选择和目标用户匹配的渠道。</p><table tabindex="0"><thead><tr><th>渠道</th><th>优势</th><th>劣势</th><th>适用场景</th></tr></thead><tbody><tr><td>App内弹窗</td><td>精准触达活跃用户</td><td>打扰用户、样本偏向活跃用户</td><td>PMF验证后的迭代调研</td></tr><tr><td>公众号推送</td><td>触达已关注用户</td><td>样本偏差（关注者≠全量用户）</td><td>探索性调研</td></tr><tr><td>社群投放</td><td>用户配合度高</td><td>样本量有限</td><td>单次调研</td></tr><tr><td>付费样本库</td><td>样本覆盖均衡</td><td>成本高、质量参差</td><td>大规模大规模验证</td></tr><tr><td>线下拦截</td><td>样本最随机</td><td>成本极高</td><td>全量用户覆盖</td></tr></tbody></table><p><strong>投放时机</strong></p><p>一个好的投放时机比一个好的问卷更重要。</p><p>合适时机：用户刚完成某个核心操作后（如完成订单、发布内容） 较差时机：用户刚打开App时（打扰用户、完成率低） 不合适时机：用户正在使用核心功能时（打断体验、样本偏差）</p><blockquote><p>回收300份有效问卷就可以得到统计上可信的结论，但前提是问卷设计本身没有偏差。问卷的质量远胜于数量。</p></blockquote><h3 id="_4-1-4-用户反馈的提炼与归纳" tabindex="-1">4.1.4 用户反馈的提炼与归纳 <a class="header-anchor" href="#_4-1-4-用户反馈的提炼与归纳" aria-label="Permalink to “4.1.4 用户反馈的提炼与归纳”">​</a></h3><p>用户反馈是产品迭代的&quot;燃料&quot;，但燃料需要提炼才能使用。大部分产品经理的问题是：收集了一堆反馈，不知道怎么用。</p><p><strong>反馈分类框架</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>定义</th><th>处理方法</th></tr></thead><tbody><tr><td>功能请求</td><td>用户明确要求某个功能</td><td>放入需求池评估优先级</td></tr><tr><td>体验反馈</td><td>用户抱怨使用体验</td><td>评估体验优化方案</td></tr><tr><td>Bug报告</td><td>用户发现产品缺陷</td><td>走Bug处理流程</td></tr><tr><td>表扬</td><td>用户表达满意</td><td>纳入案例库给团队鼓劲</td></tr><tr><td>投诉</td><td>用户极度不满</td><td>优先处理，涉及核心体验的立即修复</td></tr></tbody></table><p><strong>反馈提炼三步法</strong></p><p>第一步：去重归类。同一个反馈出现3次就是&quot;普遍问题&quot;，出现1次可能是&quot;个案&quot;。</p><p>第二步：分析原因。用户说的&quot;加载太慢&quot;，可能不是性能问题，而是用户不理解进度提示。要穿透表面，找到根本原因。</p><p>第三步：确定优先级。反馈的优先级公式是：</p><p>反馈优先级 = 影响用户数 × 影响频率 × 影响严重度 × 解决方案成本（反向）</p><p>影响用户数：有多少用户会受影响 影响频率：用户多久会遇到一次 影响严重度：对用户体验的伤害程度 解决方案成本：需要多少资源来解决</p><p><strong>反馈闭环</strong></p><p>收集反馈 → 提炼归类 → 评估优先级 → 推动解决 → 回复用户</p><p>没有闭环的反馈管理等于白做。既浪费了用户的信任，也浪费了团队的时间。</p><blockquote><p>用户反馈中90%都是噪音，但剩下的10%决定了产品的方向。区分噪音和信号的能力，是产品经理是否成熟的重要标志。</p></blockquote><h2 id="_4-2-需求管理与优先级" tabindex="-1">4.2 需求管理与优先级 <a class="header-anchor" href="#_4-2-需求管理与优先级" aria-label="Permalink to “4.2 需求管理与优先级”">​</a></h2><h3 id="_4-2-1-需求真伪识别方法" tabindex="-1">4.2.1 需求真伪识别方法 <a class="header-anchor" href="#_4-2-1-需求真伪识别方法" aria-label="Permalink to “4.2.1 需求真伪识别方法”">​</a></h3><p>怎么判断一个需求是真的还是假的？我总结了一个&quot;需求真伪四问&quot;框架。</p><p><strong>一问：用户真的会为此付费/付出吗？</strong></p><p>假需求的特征：用户说&quot;如果有这个功能我会经常用&quot;，但实际上线后发现使用率极低。</p><p>区分方法：不要说&quot;你愿意用这个功能吗&quot;，要说&quot;如果有两个选择：A有这个功能但贵10元，B没有这个功能但便宜10元，你选哪个&quot;。真实的取舍才能测试出需求是否真实。</p><p><strong>二问：这个需求是&quot;痛点&quot;还是&quot;痒点&quot;？</strong></p><p>痛点：不解决就难受，用户会主动寻找替代方案 痒点：有比没有好，但用户不会因为没有它而离开</p><p>区分方法：看用户为了解决这个问题付出了什么代价。如果用户已经在用各种笨办法解决，是真痛点。如果用户只是说说但什么都没做，是假需求。</p><p><strong>三问：这个需求的使用频率和场景是什么？</strong></p><p>高频场景下的需求优先级高，低频场景下的需求优先级低。你花了同样的研发成本，一个功能用户每天用，一个功能用户每周用一次，前者的ROI高5倍。</p><p><strong>四问：解决了这个需求对商业目标有什么帮助？</strong></p><p>需求的最终目的是服务于商业目标。如果解决了一个需求但不会对留存、时长、收入有任何影响，这个需求可能并不那么重要。</p><blockquote><p>识别需求真伪不需要很高深的方法，只需要问&quot;如果这个功能不做，用户会怎样&quot;。如果答案是&quot;会继续用&quot;——这是伪需求。如果答案是&quot;可能会离开&quot;——这是真需求。</p></blockquote><p><strong>需求真伪判定矩阵</strong></p><table tabindex="0"><thead><tr><th>判定标准</th><th>真需求</th><th>伪需求</th></tr></thead><tbody><tr><td>用户付费意愿</td><td>愿意付费/换替代方案</td><td>说说而已，不切实际</td></tr><tr><td>问题严重性</td><td>痛点，不解决难受</td><td>痒点，无所谓</td></tr><tr><td>使用频率</td><td>高频场景</td><td>低频偶发</td></tr><tr><td>商业价值</td><td>正向影响关键指标</td><td>对指标无影响</td></tr></tbody></table><h3 id="_4-2-2-需求分类管理-功能-体验-商业-技术" tabindex="-1">4.2.2 需求分类管理（功能/体验/商业/技术） <a class="header-anchor" href="#_4-2-2-需求分类管理-功能-体验-商业-技术" aria-label="Permalink to “4.2.2 需求分类管理（功能/体验/商业/技术）”">​</a></h3><p>不是所有需求都是&quot;功能需求&quot;。把需求分类管理，是高效处理需求的前提。</p><p><strong>需求四分类</strong></p><table tabindex="0"><thead><tr><th>类别</th><th>定义</th><th>举例</th><th>评估标准</th></tr></thead><tbody><tr><td>功能需求</td><td>用户能用产品做什么</td><td>增加搜索功能</td><td>功能完整度、使用率</td></tr><tr><td>体验需求</td><td>用户使用产品时的感受</td><td>优化加载速度</td><td>满意度、NPS</td></tr><tr><td>商业需求</td><td>产品如何创造价值</td><td>接入广告系统</td><td>收入、转化率</td></tr><tr><td>技术需求</td><td>支撑产品的技术能力</td><td>重构数据库</td><td>性能指标、稳定性</td></tr></tbody></table><p><strong>分类管理的核心逻辑</strong></p><p>每一类需求的管理方式不同：</p><p>功能需求：用产品规划和版本迭代管理。列入Roadmap，按优先级排入版本。</p><p>体验需求：持续优化。可以单独设立&quot;体验优化专项&quot;，批量处理这类需求。</p><p>商业需求：由产品负责人或业务团队驱动。需要评估投入产出比。</p><p>技术需求：由技术团队主导，产品团队配合评估影响。有些技术需求可以长期规划，但影响用户体验的技术需求要尽快处理。</p><p><strong>需求分类动态调整</strong></p><p>同一个需求可能在不同阶段分属不同类别。比如&quot;搜索功能&quot;在新产品中是功能需求（&quot;用户能不能搜索&quot;），在成熟产品中变成体验需求（&quot;搜索结果是否精准&quot;）。分类不是一成不变的，要跟着产品的生命周期调整。</p><h3 id="_4-2-3-需求优先级评估框架-kano模型-moscow-rice" tabindex="-1">4.2.3 需求优先级评估框架（KANO模型/MoSCoW/RICE） <a class="header-anchor" href="#_4-2-3-需求优先级评估框架-kano模型-moscow-rice" aria-label="Permalink to “4.2.3 需求优先级评估框架（KANO模型/MoSCoW/RICE）”">​</a></h3><p>需求优先级是产品经理的核心决策。我常用的三个框架：</p><p><strong>KANO模型：理解需求类型</strong></p><p>KANO模型从&quot;需求满足程度&quot;和&quot;用户满意度&quot;两个维度，把需求分为五类：</p><table tabindex="0"><thead><tr><th>类型</th><th>定义</th><th>特征</th><th>举例</th></tr></thead><tbody><tr><td>基本型</td><td>必须有的功能</td><td>没有会很不满，有了也无所谓</td><td>聊天App的&quot;发送消息&quot;</td></tr><tr><td>期望型</td><td>越多越满意的功能</td><td>有了满意度显著提升</td><td>搜索的&quot;智能推荐&quot;</td></tr><tr><td>兴奋型</td><td>意想不到的功能</td><td>没有无所谓，有了很惊喜</td><td>聊天&quot;一键修图&quot;</td></tr><tr><td>无差异型</td><td>有和没有一样</td><td>不影响满意度</td><td>花哨的转场动画</td></tr><tr><td>反向型</td><td>越多越不满</td><td>做了反而有害</td><td>强制弹窗广告</td></tr></tbody></table><p>KANO模型的应用：优先保证基本型需求，重点投入期望型需求，在有余力时加入兴奋型需求，果断砍掉无差异型和反向型需求。</p><p><strong>MoSCoW方法：排定优先级</strong></p><p>MoSCoW方法把需求分为四类：</p><table tabindex="0"><thead><tr><th>优先级</th><th>含义</th><th>说明</th><th>占比</th></tr></thead><tbody><tr><td>Must have</td><td>必须有</td><td>没有这个功能产品无法上线</td><td>约20%</td></tr><tr><td>Should have</td><td>应该有</td><td>很重要但可以推迟</td><td>约30%</td></tr><tr><td>Could have</td><td>可以有</td><td>有比没有好但没有也影响不大</td><td>约30%</td></tr><tr><td>Won&#39;t have</td><td>这次不做</td><td>明确放弃的下次再做</td><td>约20%</td></tr></tbody></table><p>MoSCoW方法的应用：每个版本都需要有清晰的Must列表，确保核心功能完整。Should和Could可根据资源灵活调整。Won&#39;t需要有明确的记录，避免同样的问题反复讨论。</p><p><strong>RICE评分：量化评估</strong></p><p>RICE评分把需求优先级量化为一个数字：</p><p>RICE Score = (Reach × Impact × Confidence) / Effort</p><table tabindex="0"><thead><tr><th>维度</th><th>含义</th><th>评分标准</th></tr></thead><tbody><tr><td>Reach</td><td>影响用户数</td><td>1=极少数 2=部分 3=大部分 10=全部</td></tr><tr><td>Impact</td><td>影响程度</td><td>1=微弱 2=中等 3=显著 10=颠覆性</td></tr><tr><td>Confidence</td><td>把握度</td><td>0.2=猜测 0.5=有依据 1=有数据 1.5=已验证</td></tr><tr><td>Effort</td><td>开发成本</td><td>1=几小时 2=几天 3=几周 10=几个月</td></tr></tbody></table><p>举个例子：</p><p>需求A：增加分享功能</p><ul><li>Reach=3（大部分用户会用到）</li><li>Impact=2（有影响但不显著）</li><li>Confidence=0.5（有用户反馈，但没有数据验证）</li><li>Effort=2（需要2天开发）</li><li>Score = (3×2×0.5)/2 = 1.5</li></ul><p>需求B：优化登录流程</p><ul><li>Reach=10（所有用户都会用到）</li><li>Impact=3（简化登录对转化率影响大）</li><li>Confidence=1（有数据支撑）</li><li>Effort=1（半天就能完成）</li><li>Score = (10×3×1)/1 = 30</li></ul><p>显然需求B的优先级远高于需求A。</p><blockquote><p>RICE的四个维度可以根据产品阶段调整权重。探索期可以加大Confidence的权重，增长期可以加大Reach的权重。没有绝对正确的评分，只有适合当前阶段的评分。</p></blockquote><h3 id="_4-2-4-需求池维护与迭代规划" tabindex="-1">4.2.4 需求池维护与迭代规划 <a class="header-anchor" href="#_4-2-4-需求池维护与迭代规划" aria-label="Permalink to “4.2.4 需求池维护与迭代规划”">​</a></h3><p>需求池不是&quot;垃圾桶&quot;，而是一个需要持续维护的&quot;活系统&quot;。</p><p><strong>需求池的基本要素</strong></p><table tabindex="0"><thead><tr><th>要素</th><th>说明</th></tr></thead><tbody><tr><td>需求ID</td><td>唯一编号</td></tr><tr><td>来源</td><td>用户反馈/产品规划/运营需求/技术需求</td></tr><tr><td>描述</td><td>需求是什么，用户场景</td></tr><tr><td>价值</td><td>为什么做这个需求</td></tr><tr><td>优先级</td><td>Must/Should/Could/Won&#39;t或RICE评分</td></tr><tr><td>状态</td><td>待评估/已评估、已排期/开发中/已上线/已驳回</td></tr><tr><td>负责人</td><td>谁在跟进这个需求</td></tr><tr><td>创建时间</td><td>什么时候提出的</td></tr></tbody></table><p><strong>需求池维护周期</strong></p><p>每周做一次：需求池review，更新状态，清理已完成的</p><p>每月做一次：优先级重排，补充新需求，淘汰过时需求</p><p>每季度做一次：需求池评审，和版本规划对齐，讨论大方向</p><p><strong>迭代规划三步法</strong></p><p>第一步：固定版本周期。两周或一个月一个版本，固定节奏，不要频繁变更。</p><p>第二步：根据优先级和资源匹配确定每个版本的需求。Must优先，Should补充，Could随缘。</p><p>第三步：留10-15%的弹性空间。每个版本都要预留一些容量，应对紧急需求的插入。</p><blockquote><p>需求池管理的核心不是&quot;记录需求&quot;，而是&quot;帮助我们做更好的决策&quot;。一个清晰的需求池，能让你在面对&quot;能不能加个功能&quot;的时候，快速判断这个需求应该放在什么优先级。</p></blockquote><h2 id="_4-3-产品定位与规划" tabindex="-1">4.3 产品定位与规划 <a class="header-anchor" href="#_4-3-产品定位与规划" aria-label="Permalink to “4.3 产品定位与规划”">​</a></h2><h3 id="_4-3-1-基于市场与需求明确产品定位" tabindex="-1">4.3.1 基于市场与需求明确产品定位 <a class="header-anchor" href="#_4-3-1-基于市场与需求明确产品定位" aria-label="Permalink to “4.3.1 基于市场与需求明确产品定位”">​</a></h3><p>产品定位一张表就能说清楚：</p><p><strong>产品定位模板</strong></p><table tabindex="0"><thead><tr><th>要素</th><th>内容</th></tr></thead><tbody><tr><td>目标用户</td><td>谁会用这个产品</td></tr><tr><td>核心场景</td><td>用户在什么场景下使用</td></tr><tr><td>核心价值</td><td>用户为什么用这个产品</td></tr><tr><td>差异化</td><td>用户为什么用你不用别人</td></tr><tr><td>一句话定位</td><td>以上四个要素的整合</td></tr></tbody></table><p>举例：某笔记产品的一句话定位</p><p>&quot;给互联网从业者提供一款AI驱动的知识管理工具，让信息收集、知识整理、协作分享在一个平台上完成，比Notion更本地化、比印象笔记更智能化。&quot;</p><p><strong>产品定位的常见错误</strong></p><p>错误一：用户太多。定位太宽等于没有定位。&quot;给所有人用的笔记工具&quot;没有意义。</p><p>错误二：价值太多。能解决的问题越多，意味着没有一个问题解决得足够好。一个产品解决一个问题，做到极致。</p><p>错误三：定位一成不变。产品定位不是写一次就不变了。随着市场和用户的变化，产品定位需要动态调整。</p><h3 id="_4-3-2-产品目标设定-短期-中期-长期" tabindex="-1">4.3.2 产品目标设定（短期/中期/长期） <a class="header-anchor" href="#_4-3-2-产品目标设定-短期-中期-长期" aria-label="Permalink to “4.3.2 产品目标设定（短期/中期/长期）”">​</a></h3><p>有了定位之后，需要把定位转化为可衡量的目标。</p><p><strong>目标分层</strong></p><table tabindex="0"><thead><tr><th>时间维度</th><th>范围</th><th>目标类型</th><th>示例</th></tr></thead><tbody><tr><td>短期</td><td>1-3个月</td><td>功能目标</td><td>上线搜索V1，搜索使用率达到30%</td></tr><tr><td>中期</td><td>3-6个月</td><td>体验目标</td><td>搜索准确率提升到85%以上</td></tr><tr><td>长期</td><td>6-12个月</td><td>商业目标</td><td>搜索广告贡献10%的营收</td></tr></tbody></table><p><strong>SMART原则</strong></p><p>好目标要遵循SMART原则：</p><p>S（Specific）具体：不说&quot;提升用户体验&quot;，说&quot;提升搜索转化率&quot;</p><p>M（Measurable）可衡量：不说&quot;效果很好&quot;，说&quot;从20%提升到30%&quot;</p><p>A（Achievable）可实现：有客观条件支撑</p><p>R（Relevant）相关：和产品定位一致</p><p>T（Time-bound）有时限：有明确的完成时间</p><h3 id="_4-3-3-产品路线图-roadmap-规划" tabindex="-1">4.3.3 产品路线图（Roadmap）规划 <a class="header-anchor" href="#_4-3-3-产品路线图-roadmap-规划" aria-label="Permalink to “4.3.3 产品路线图（Roadmap）规划”">​</a></h3><p>产品路线图是产品目标的&quot;外化表达&quot;。</p><p><strong>一个好的Roadmap包含什么</strong></p><p>时间轴：现在是哪个月，重要的里程碑在哪 功能规划：每个时间窗口要做什么功能 目标和指标：每个功能上线后要达到什么指标</p><p><strong>Roadmap不是排期表</strong></p><p>产品经理最常见的错误：把Roadmap当成&quot;研发排期表&quot;。实际上，Roadmap是&quot;产品方向表达&quot;，不是&quot;排期承诺&quot;。</p><p>好的Roadmap看起来是这样的：</p><p>Q1：上线社区MVP，验证用户有没有社交需求 Q2：根据数据优化社区，引入话题系统 Q3：探索商业化可能，上线虚拟道具 Q4：完善会员体系，提升付费转化</p><p>而不是：</p><p>1月15日：完成社区V1需求评审 2月1日：开始开发社区V1 3月15日：社区V1上线</p><p>Roadmap的核心是&quot;方向承诺&quot;而非&quot;排期承诺&quot;。</p><h3 id="_4-3-4-产品方向决策-每一步做什么" tabindex="-1">4.3.4 产品方向决策：每一步做什么 <a class="header-anchor" href="#_4-3-4-产品方向决策-每一步做什么" aria-label="Permalink to “4.3.4 产品方向决策：每一步做什么”">​</a></h3><p>产品方向决策是最难的。不是因为没有信息，而是因为信息太多。</p><p><strong>决策框架</strong></p><p>第一步：看数据。当前产品数据告诉你什么？用户在哪一步流失？哪个功能使用率高但满意度低？</p><p>第二步：看用户。用户反馈中最核心的问题是什么？解决了这个问题能带来多大的商业价值？</p><p>第三步：看竞品。竞品在做什么？他们做得好吗？有没有我们可以做的差异化空间？</p><p>第四步：看资源。团队有什么能力和资源？有什么制约条件？</p><p><strong>决策优先级</strong></p><p>当多个方向摆在面前时，按这个顺序判断：</p><ol><li>修复核心体验缺陷（做了不会让数据更好看，但不做数据会下降）</li><li>验证高回报假设（做了可能带来显著增长）</li><li>优化已有功能（做了能提升数据和满意度）</li><li>增加新功能（做了能丰富产品能力）</li><li>修补非核心缺陷（做了能提升边际体验）</li></ol><hr><p>本章小结：需求管理和产品定位是产品经理的日常工作，但大多数产品经理在处理需求时都是&quot;来者不拒&quot;，导致产品功能堆砌、定位模糊。好的产品经理，是在有限资源下做出最好的选择。</p><table tabindex="0"><thead><tr><th>本章核心知识点</th><th>一句话总结</th></tr></thead><tbody><tr><td>调研方法选择</td><td>探索用访谈，验证用AB测试，监测看数据</td></tr><tr><td>需求真伪四问</td><td>付费吗？痛点吗？高频吗？有商业价值吗？</td></tr><tr><td>需求四分类</td><td>功能/体验/商业/技术，分类管理</td></tr><tr><td>KANO模型</td><td>基本型必须做，期望型重点做，兴奋型锦上添花</td></tr><tr><td>MoSCoW</td><td>Must/Should/Could/Won&#39;t，明确优先级</td></tr><tr><td>RICE评分</td><td>Reach×Impact×Confidence÷Effort</td></tr><tr><td>产品定位</td><td>目标用户+核心场景+核心价值+差异化</td></tr></tbody></table><p>觉得有用？收藏起来，下次做需求调研时直接照抄模板。</p><p>你被假需求坑过吗？评论区说说你的经历。</p><p>关注怕浪猫，下期我们讲&quot;搭建产品架构&quot;——1张表、4张图，把产品从想法变成一个可落地的架构方案。</p><p>系列进度 4/16</p><p><strong>下章预告：</strong> 第5章是最实操的一章。一张功能清单表，四张核心图（信息架构图、功能架构图、业务流程图、状态机图），就能把任何产品的架构搭得清清楚楚。怕浪猫不讲理论，直接教你怎么画。</p>',178)])])}const b=d(a,[["render",e]]);export{s as __pageData,b as default};
